// The webhook can receive either a single object or an array.
// We normalize to always work with one clean object.
const raw = $input.first().json;

// Case 1: Postman sends array of objects with {headers, body, ...}
// Case 2: Cowork sends body directly
let body;
if (Array.isArray(raw) && raw[0] && raw[0].body) {
  body = raw[0].body;
} else if (raw.body && typeof raw.body === 'object') {
  body = raw.body;
} else {
  body = raw;
}

if (!body.original_concepts || !Array.isArray(body.original_concepts)) {
  throw new Error('Invalid payload: original_concepts missing');
}

return [{ json: body }];

// Extract the selected concept from the normalized payload
const body = $('Normalize Payload').first().json;
const concepts = body.original_concepts || [];
const selectedId = body.selected_concept_id || 1;
const selected = concepts.find(c => c.concept_id === selectedId) || concepts[0];

if (!selected) {
  throw new Error('No concept found in payload');
}

return [{
  json: {
    concept_id: selected.concept_id,
    title: selected.title,
    hook: selected.hook,
    storyline: selected.storyline,
    visual_description: selected.visual_description,
    suggested_caption: selected.suggested_caption,
    why_viral: selected.why_viral,
    viral_pattern: body.viral_pattern,
    niche: body.niche,
    run_date: body.run_date
  }
}];

// Parse Claude's JSON response safely
const claudeResponse = $input.first().json;
const textBlock = (claudeResponse.content || []).find(c => c.type === 'text');
if (!textBlock) throw new Error('No text block in Claude response');

let raw = textBlock.text.trim();
// Strip potential markdown fences
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/,'').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error('Claude did not return valid JSON: ' + raw.substring(0, 300));
}

const concept = $('Select Concept').first().json;

return [{
  json: {
    video_prompt: parsed.video_prompt,
    tiktok_caption: parsed.tiktok_caption,
    duration_sec: 4,
    concept_title: concept.title,
    concept_hook: concept.hook,
    concept_storyline: concept.storyline
  }
}];

const r = $input.first().json;
const data = r.data || r;
const videoUrl = (data.outputs && data.outputs[0]) || data.output || data.video_url;
if (!videoUrl) throw new Error('No video URL found in Seedance response: ' + JSON.stringify(data).substring(0, 300));

const parsed = $('Parse Claude Output').first().json;
const startResp = $('Seedance - Start Generation').first().json;
const predictionId = startResp.id || startResp.data?.id;

return [{
  json: {
    video_url: videoUrl,
    prediction_id: predictionId,
    concept_title: parsed.concept_title,
    concept_hook: parsed.concept_hook,
    concept_storyline: parsed.concept_storyline,
    video_prompt: parsed.video_prompt,
    tiktok_caption: parsed.tiktok_caption
  }
}];
